(function() {
'use strict';
const { useState } = React;

const COTIZACION_USD = 1000.00;

const FormularioPVC = () => {
    const [descripcion, setDescripcion] = useState('');
    const [cantidad, setCantidad] = useState(1);
    const [valorUsd, setValorUsd] = useState(0);
    const [margen, setMargen] = useState(30);
    const [saving, setSaving] = useState(false);

    const valorPesos = valorUsd * COTIZACION_USD;
    const precioConMargenUsd = valorUsd * (1 + margen / 100);
    const precioTotalUsd = precioConMargenUsd * cantidad;
    const fmt = n => (n || 0).toLocaleString('es-AR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

    const guardar = () => {
        if (!descripcion.trim()) {
            alert('Ingresa una descripción');
            return;
        }
        if (valorUsd <= 0) {
            alert('Ingresa un valor en USD mayor a 0');
            return;
        }
        setSaving(true);
        document.getElementById('f-pvc-descripcion').value = descripcion;
        document.getElementById('f-pvc-cantidad').value = cantidad;
        document.getElementById('f-pvc-valor-usd').value = valorUsd.toFixed(2);
        document.getElementById('f-pvc-margen').value = margen;
        document.getElementById('item-save-form-pvc').submit();
    };

    if (!COTIZACION_USD) {
        return (
            <div className="text-sm text-amber-700 bg-amber-50 border border-amber-200 rounded-lg p-4">
                <i className="fas fa-exclamation-triangle mr-2"></i>
                Este presupuesto en PVC todavía no tiene una cotización USD configurada. Editá el presupuesto y completá la cotización antes de agregar ítems.
            </div>
        );
    }

    return (
        <div className="space-y-4">
            <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Descripción</label>
                <input type="text" value={descripcion} onChange={e => setDescripcion(e.target.value)}
                    placeholder="Ej: Ventana PVC 120x150"
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500" />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Cantidad</label>
                    <input type="number" min="1" value={cantidad} onChange={e => setCantidad(Math.max(1, parseInt(e.target.value)||1))}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Margen (%)</label>
                    <input type="number" step="0.01" value={margen} onChange={e => setMargen(parseFloat(e.target.value)||0)}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
            </div>

            <div className="border-t pt-4">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Valor en USD</label>
                <input type="number" step="0.01" min="0" value={valorUsd} onChange={e => setValorUsd(parseFloat(e.target.value)||0)}
                    placeholder="0.00"
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500" />
                <p className="mt-2 text-xs text-slate-500">
                    Cotización del presupuesto: <strong>${fmt(COTIZACION_USD)}</strong>
                    {valorUsd > 0 && <> · Equivalente en pesos: <strong>${fmt(valorPesos)}</strong></>}
                </p>
            </div>

            {valorUsd > 0 && (
                <div className="bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl p-4 text-white">
                    <div className="flex justify-between items-center mb-2">
                        <span className="text-sm opacity-80">Precio unitario con margen</span>
                        <span className="text-xl font-bold">US${fmt(precioConMargenUsd)}</span>
                    </div>
                    {cantidad > 1 && (
                        <div className="flex justify-between items-center border-t border-white/20 pt-2">
                            <span className="text-sm opacity-80">Total ({cantidad} unidades)</span>
                            <span className="text-2xl font-bold">US${fmt(precioTotalUsd)}</span>
                        </div>
                    )}
                </div>
            )}

            <button onClick={guardar} disabled={saving}
                className="w-full bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 disabled:opacity-50 text-white py-3 rounded-xl font-bold transition-all flex items-center justify-center">
                {saving ? <><i className="fas fa-spinner fa-spin mr-2"></i>Guardando...</> : <><i className="fas fa-check mr-2"></i>Agregar al presupuesto</>}
            </button>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('formulario-pvc'));
root.render(<FormularioPVC />);
})();

