(function() {
'use strict';
const { useState, useEffect } = React;

// -- Componente Select con busqueda --
const Sel = ({ label, options, value, onChange, placeholder, disabled = false }) => {
    const [search, setSearch] = useState('');
    const [isOpen, setIsOpen] = useState(false);
    const filtered = options.filter(opt => (opt.nombre || opt.descripcion || opt.codigo || '').toLowerCase().includes(search.toLowerCase()));
    const selected = options.find(opt => (opt.id && opt.id === value) || (opt.codigo && opt.codigo === value));
    const selectedText = selected ? (selected.nombre || selected.descripcion || selected.codigo) : placeholder;

    return (
        <div className="mb-3">
            <label className="block text-xs font-semibold text-slate-600 mb-1 uppercase tracking-wide">{label}</label>
            <div className="relative">
                <button type="button" disabled={disabled} onClick={() => !disabled && setIsOpen(!isOpen)}
                    className={`w-full px-3 py-2 text-left border rounded-lg bg-white text-sm transition-colors ${disabled ? 'border-gray-200 text-gray-400 cursor-not-allowed bg-gray-50' : 'border-gray-300 hover:border-blue-400 focus:outline-none focus:ring-2 focus:ring-blue-500'}`}>
                    <span className={selected ? 'text-gray-900' : 'text-gray-400'}>{selectedText}</span>
                    {!disabled && <i className="fas fa-chevron-down absolute right-3 top-1/2 -translate-y-1/2 text-gray-300 text-xs pointer-events-none"></i>}
                </button>
                {isOpen && (
                    <>
                        <div className="fixed inset-0 z-10" onClick={() => setIsOpen(false)} />
                        <div className="absolute z-20 w-full mt-1 bg-white border border-gray-200 rounded-xl shadow-xl max-h-56 overflow-hidden">
                            <div className="p-2 border-b">
                                <input autoFocus type="text" value={search} onChange={e => setSearch(e.target.value)}
                                    onClick={e => e.stopPropagation()} placeholder="Buscar..."
                                    className="w-full px-3 py-1.5 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
                            </div>
                            <div className="overflow-y-auto max-h-44">
                                <button type="button" onClick={() => { onChange(null); setIsOpen(false); setSearch(''); }}
                                    className="w-full px-3 py-2 text-left text-sm text-gray-400 hover:bg-gray-50">— Ninguno —</button>
                                {filtered.map(opt => (
                                    <button key={opt.id || opt.codigo} type="button"
                                        onClick={() => { onChange(opt.id || opt.codigo); setIsOpen(false); setSearch(''); }}
                                        className={`w-full px-3 py-2 text-left text-sm ${value === (opt.id || opt.codigo) ? 'bg-blue-50 text-blue-700 font-semibold' : 'hover:bg-slate-50 text-gray-800'}`}>
                                        {opt.nombre || opt.descripcion || opt.codigo}
                                    </button>
                                ))}
                                {filtered.length === 0 && <div className="px-3 py-3 text-sm text-gray-400 text-center">Sin resultados</div>}
                            </div>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
};

// -- Modal de opcionales --
const OpcionalesModal = ({ opcionales, onSelect }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [search, setSearch] = useState('');
    const filtered = opcionales.filter(opt => `${opt.codigo} ${opt.nombre}`.toLowerCase().includes(search.toLowerCase()));

    return (
        <>
            <button type="button" onClick={() => setIsOpen(true)}
                className="w-full bg-blue-50 text-blue-600 py-2.5 rounded-lg border-2 border-dashed border-blue-300 hover:bg-blue-100 transition flex items-center justify-center text-sm font-semibold">
                <i className="fas fa-plus mr-2"></i>Agregar Opcional
            </button>

            {isOpen && (
                <>
                    <div className="fixed inset-0 bg-black bg-opacity-50 z-[60]" onClick={() => setIsOpen(false)} />
                    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                        <div className="bg-white rounded-2xl shadow-xl max-w-2xl w-full max-h-[80vh] overflow-hidden">
                            <div className="p-5 border-b">
                                <div className="flex justify-between items-center mb-3">
                                    <h3 className="text-lg font-bold text-slate-800">
                                        <i className="fas fa-plus-circle mr-2 text-blue-600"></i>Seleccionar Opcional
                                    </h3>
                                    <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-gray-600 text-xl">
                                        <i className="fas fa-times"></i>
                                    </button>
                                </div>
                                <input type="text" value={search} onChange={e => setSearch(e.target.value)}
                                    placeholder="Buscar por codigo o nombre..."
                                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500" />
                            </div>
                            <div className="overflow-y-auto max-h-96 p-5">
                                {filtered.length === 0 ? (
                                    <div className="text-center py-8 text-gray-400">
                                        <i className="fas fa-search text-4xl mb-3 opacity-50"></i>
                                        <p>No se encontraron opcionales</p>
                                    </div>
                                ) : (
                                    <div className="space-y-2">
                                        {filtered.map(opcional => (
                                            <button key={opcional.id} onClick={() => { onSelect(opcional); setIsOpen(false); setSearch(''); }}
                                                className="w-full text-left p-4 border border-gray-200 rounded-lg hover:bg-blue-50 hover:border-blue-300 transition">
                                                <div className="flex justify-between items-start">
                                                    <div className="flex-1">
                                                        <div className="font-medium text-gray-900">{opcional.codigo} - {opcional.nombre}</div>
                                                        <div className="text-sm text-gray-500 mt-1">
                                                            {opcional.tipo === 'mosquitero'
                                                                ? <span><i className="fas fa-dollar-sign mr-1"></i>${opcional.precio_m2.toLocaleString('es-AR')}/m2</span>
                                                                : <span><i className="fas fa-calculator mr-1"></i>Calculado por formulas</span>
                                                            }
                                                        </div>
                                                    </div>
                                                    <span className={`px-3 py-1 rounded-full text-xs font-medium ${opcional.tipo === 'mosquitero' ? 'bg-blue-100 text-blue-800' : 'bg-green-100 text-green-800'}`}>
                                                        {opcional.tipo === 'mosquitero' ? 'Mosquitero' : 'Otro'}
                                                    </span>
                                                </div>
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </>
            )}
        </>
    );
};

// -- Componente de desglose expandible --
const DesgloseSection = ({ title, icon, color, total, children }) => {
    const fmt = n => (n || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 });
    return (
        <details className={`mb-2 bg-${color}-50 rounded-lg`} open>
            <summary className={`cursor-pointer p-3 font-medium text-${color}-900 hover:bg-${color}-100 rounded-lg`}>
                <span className="inline-flex items-center justify-between w-full">
                    <span><i className={`fas ${icon} mr-2`}></i>{title}</span>
                    <span className={`text-${color}-700`}>${fmt(total)}</span>
                </span>
            </summary>
            <div className="p-3 pt-0 space-y-1">{children}</div>
        </details>
    );
};

const DesgloseItem = ({ left, right, detail, color = 'blue' }) => (
    <div className="bg-white p-2 rounded text-sm">
        <div className="flex justify-between font-medium">
            <span className="text-gray-800">{left}</span>
            <span className={`text-${color}-600`}>${(right || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 })}</span>
        </div>
        {detail && <div className="text-xs text-gray-500 mt-0.5">{detail}</div>}
    </div>
);

// -- Componente principal --
const CotizadorModal = () => {
    const [config, setConfig] = useState({
        extrusora_id: null, linea_id: null, producto_id: null,
        marco_id: null, hoja_id: null, vidrio_codigo: null,
        interior_id: null, tratamiento_id: null,
        ancho_mm: 1200, alto_mm: 1500, margen_porcentaje: 30,
        opcionales: [],
    });
    const [descripcion, setDescripcion] = useState('');
    const [cantidad, setCantidad] = useState(1);
    const [extrusoras, setExtrusoras] = useState([]);
    const [lineas, setLineas] = useState([]);
    const [productos, setProductos] = useState([]);
    const [marcos, setMarcos] = useState([]);
    const [hojas, setHojas] = useState([]);
    const [vidrios, setVidrios] = useState([]);
    const [interiores, setInteriores] = useState([]);
    const [tratamientos, setTratamientos] = useState([]);
    const [opcionalesDisp, setOpcionalesDisp] = useState([]);
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState(null);

    useEffect(() => {
        fetch('/pricing/api/pricing/extrusoras/').then(r => r.json()).then(setExtrusoras);
        fetch('/pricing/api/pricing/tratamientos/').then(r => r.json()).then(setTratamientos);
    }, []);
    useEffect(() => {
        if (config.extrusora_id) fetch(`/pricing/api/pricing/lineas/?extrusora_id=${config.extrusora_id}`).then(r => r.json()).then(setLineas);
        else setLineas([]);
    }, [config.extrusora_id]);
    useEffect(() => {
        if (config.linea_id) fetch(`/pricing/api/pricing/productos/?linea_id=${config.linea_id}`).then(r => r.json()).then(setProductos);
        else setProductos([]);
    }, [config.linea_id]);
    useEffect(() => {
        if (config.producto_id) {
            fetch(`/pricing/api/pricing/marcos/?producto_id=${config.producto_id}`).then(r => r.json()).then(setMarcos);
            fetch(`/pricing/api/pricing/opcionales/?producto_id=${config.producto_id}`).then(r => r.json()).then(setOpcionalesDisp);
        } else { setMarcos([]); setOpcionalesDisp([]); }
    }, [config.producto_id]);
    useEffect(() => {
        if (config.marco_id) fetch(`/pricing/api/pricing/hojas/?marco_id=${config.marco_id}`).then(r => r.json()).then(setHojas);
        else setHojas([]);
    }, [config.marco_id]);
    useEffect(() => {
        if (config.hoja_id) {
            fetch(`/pricing/api/pricing/interiores/?hoja_id=${config.hoja_id}`).then(r => r.json()).then(setInteriores);
            fetch(`/pricing/api/pricing/vidrios/?hoja_id=${config.hoja_id}`).then(r => r.json()).then(setVidrios);
        } else { setInteriores([]); setVidrios([]); }
    }, [config.hoja_id]);

    const calcular = async () => {
        if (!config.marco_id) { setError('Selecciona un marco primero'); return; }
        setLoading(true); setError(null);
        try {
            const csrf = document.querySelector('[name=csrfmiddlewaretoken]').value;
            const res = await fetch('/pricing/api/pricing/calculate/', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'X-CSRFToken': csrf },
                body: JSON.stringify(config),
            });
            if (!res.ok) { const e = await res.json().catch(() => ({})); throw new Error(e.detail || e.error || 'Error al calcular'); }
            setResult(await res.json());
        } catch(e) { setError(e.message); }
        finally { setLoading(false); }
    };

    const guardar = () => {
        if (!result) { setError('Calcula el precio primero'); return; }
        setSaving(true);
        document.getElementById('f-producto_id').value = config.producto_id || '';
        document.getElementById('f-marco_id').value = config.marco_id || '';
        document.getElementById('f-hoja_id').value = config.hoja_id || '';
        document.getElementById('f-vidrio_codigo').value = config.vidrio_codigo || '';
        document.getElementById('f-interior_id').value = config.interior_id || '';
        document.getElementById('f-tratamiento_id').value = config.tratamiento_id || '';
        document.getElementById('f-ancho_mm').value = config.ancho_mm;
        document.getElementById('f-alto_mm').value = config.alto_mm;
        document.getElementById('f-margen_porcentaje').value = config.margen_porcentaje;
        document.getElementById('f-descripcion').value = descripcion || `Abertura ${config.ancho_mm}x${config.alto_mm}mm`;
        document.getElementById('f-cantidad').value = cantidad;
        document.getElementById('f-opcionales_json').value = JSON.stringify(config.opcionales.map(o => ({ id: o.id })));
        document.getElementById('item-save-form').submit();
    };

    const fmt = n => (n || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 });
    const set = (k, v, reset = {}) => setConfig(c => ({ ...c, [k]: v, ...reset }));

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

            {/* Configuracion */}
            <div>
                <div className="grid grid-cols-3 gap-3 mb-4">
                    <div className="col-span-2">
                        <label className="block text-xs font-semibold text-slate-600 mb-1 uppercase tracking-wide">Descripcion</label>
                        <input type="text" value={descripcion} onChange={e => setDescripcion(e.target.value)}
                            placeholder="Ej: Ventana cocina"
                            className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-600 mb-1 uppercase tracking-wide">Cantidad</label>
                        <input type="number" min="1" value={cantidad} onChange={e => setCantidad(Math.max(1, parseInt(e.target.value)||1))}
                            className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500" />
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-x-4">
                    <Sel label="Extrusora" options={extrusoras} value={config.extrusora_id}
                        onChange={v => set('extrusora_id', v, { linea_id:null, producto_id:null, marco_id:null, hoja_id:null, vidrio_codigo:null, interior_id:null, opcionales:[] })}
                        placeholder="Seleccionar..." />
                    <Sel label="Linea" options={lineas} value={config.linea_id} disabled={!config.extrusora_id}
                        onChange={v => set('linea_id', v, { producto_id:null, marco_id:null, hoja_id:null, vidrio_codigo:null, interior_id:null, opcionales:[] })}
                        placeholder={config.extrusora_id ? "Seleccionar..." : "Primero extrusora"} />
                    <Sel label="Producto" options={productos} value={config.producto_id} disabled={!config.linea_id}
                        onChange={v => set('producto_id', v, { marco_id:null, hoja_id:null, vidrio_codigo:null, interior_id:null, opcionales:[] })}
                        placeholder={config.linea_id ? "Seleccionar..." : "Primero linea"} />
                    <Sel label="Marco *" options={marcos} value={config.marco_id} disabled={!config.producto_id}
                        onChange={v => set('marco_id', v, { hoja_id:null, vidrio_codigo:null, interior_id:null })}
                        placeholder={config.producto_id ? "Seleccionar..." : "Primero producto"} />
                    <Sel label="Hoja (opcional)" options={hojas} value={config.hoja_id} disabled={!config.marco_id}
                        onChange={v => set('hoja_id', v, { vidrio_codigo:null, interior_id:null })}
                        placeholder={config.marco_id ? "Seleccionar..." : "Primero marco"} />
                    {config.hoja_id && vidrios.length > 0
                        ? <Sel label="Vidrio" options={vidrios} value={config.vidrio_codigo}
                            onChange={v => set('vidrio_codigo', v)} placeholder="Seleccionar..." />
                        : <div />
                    }
                    {config.hoja_id && interiores.length > 0
                        ? <Sel label="Interior (opcional)" options={interiores} value={config.interior_id}
                            onChange={v => set('interior_id', v)} placeholder="Seleccionar..." />
                        : <div />
                    }
                    <Sel label="Tratamiento (opcional)" options={tratamientos} value={config.tratamiento_id}
                        onChange={v => set('tratamiento_id', v)} placeholder="Sin tratamiento" />
                </div>

                <div className="grid grid-cols-3 gap-3 mt-1">
                    {[['Ancho (mm)', 'ancho_mm'], ['Alto (mm)', 'alto_mm'], ['Margen (%)', 'margen_porcentaje']].map(([lbl, key]) => (
                        <div key={key}>
                            <label className="block text-xs font-semibold text-slate-600 mb-1 uppercase tracking-wide">{lbl}</label>
                            <input type="number" value={config[key]}
                                onChange={e => setConfig(c => ({ ...c, [key]: parseFloat(e.target.value) || 0 }))}
                                className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500" />
                        </div>
                    ))}
                </div>

                {/* Opcionales */}
                {config.producto_id && opcionalesDisp.length > 0 && (
                    <div className="mt-4 border-t pt-4">
                        <label className="block text-xs font-semibold text-slate-600 mb-2 uppercase tracking-wide">
                            <i className="fas fa-plus-circle mr-1 text-blue-600"></i>Opcionales
                        </label>
                        {config.opcionales.length > 0 && (
                            <div className="mb-2 space-y-1.5">
                                {config.opcionales.map((opc, idx) => (
                                    <div key={idx} className="bg-gray-50 p-2.5 rounded-lg border border-gray-200 flex items-center justify-between">
                                        <div>
                                            <div className="font-medium text-sm text-gray-800">{opc.codigo} - {opc.nombre}</div>
                                            <div className="text-xs text-gray-500">
                                                {opc.tipo === 'mosquitero' ? `$${opc.precio_m2.toLocaleString('es-AR')}/m2` : 'Calculado por formulas'}
                                            </div>
                                        </div>
                                        <button onClick={() => setConfig(c => ({ ...c, opcionales: c.opcionales.filter((_, i) => i !== idx) }))}
                                            className="text-red-500 hover:text-red-700 p-1.5" title="Quitar">
                                            <i className="fas fa-trash text-xs"></i>
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                        <OpcionalesModal opcionales={opcionalesDisp}
                            onSelect={opcional => {
                                if (!config.opcionales.find(o => o.id === opcional.id)) {
                                    setConfig(c => ({ ...c, opcionales: [...c.opcionales, opcional] }));
                                }
                            }} />
                    </div>
                )}

                {error && <div className="mt-3 bg-red-50 border border-red-200 text-red-700 px-3 py-2 rounded-lg text-sm">{error}</div>}

                <button onClick={calcular} disabled={loading || !config.marco_id}
                    className="w-full mt-4 bg-blue-600 hover:bg-blue-700 disabled:bg-gray-200 disabled:text-gray-400 text-white py-2.5 rounded-xl font-semibold text-sm transition-colors flex items-center justify-center">
                    {loading ? <><i className="fas fa-spinner fa-spin mr-2"></i>Calculando...</> : <><i className="fas fa-calculator mr-2"></i>Calcular precio</>}
                </button>
            </div>

            {/* Resultado */}
            <div className="flex flex-col">
                {result ? (
                    <>
                        <div className="bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl p-5 text-white mb-4">
                            <p className="text-sm opacity-80 mb-1">Precio unitario</p>
                            <p className="text-4xl font-bold">${fmt(result.precio_total)}</p>
                            {cantidad > 1 && <p className="text-sm opacity-80 mt-2">x {cantidad} = <strong>${fmt(result.precio_total * cantidad)}</strong></p>}
                            <div className="flex gap-4 mt-2 text-sm opacity-80">
                                <span>Subtotal: ${fmt(result.subtotal)}</span>
                                <span>Margen ({config.margen_porcentaje}%): ${fmt(result.margen)}</span>
                            </div>
                        </div>

                        <div className="flex-1 space-y-0">
                            {/* Perfiles */}
                            {result.desglose.perfiles && result.desglose.perfiles.length > 0 && (
                                <DesgloseSection title={`Perfiles (${result.desglose.perfiles.length})`} icon="fa-ruler" color="blue" total={result.resumen.total_perfiles}>
                                    {result.desglose.perfiles.map((item, idx) => (
                                        <DesgloseItem key={idx} color="blue"
                                            left={`${item.codigo} - ${item.descripcion}`}
                                            right={item.precio_total}
                                            detail={`Cant: ${item.cantidad} x ${item.longitud_mm}mm (${item.longitud_m}m) | ${item.peso_kg}kg x $${item.precio_kg}/kg${item.angulo ? ` | Angulo: ${item.angulo}` : ''}`} />
                                    ))}
                                </DesgloseSection>
                            )}
                            {/* Accesorios */}
                            {result.desglose.accesorios && result.desglose.accesorios.length > 0 && (
                                <DesgloseSection title={`Accesorios (${result.desglose.accesorios.length})`} icon="fa-tools" color="green" total={result.resumen.total_accesorios}>
                                    {result.desglose.accesorios.map((item, idx) => (
                                        <DesgloseItem key={idx} color="green"
                                            left={`${item.codigo} - ${item.descripcion}`}
                                            right={item.precio_total}
                                            detail={`Cantidad: ${item.cantidad} x $${fmt(item.precio_unitario)}${item.dimensiones ? ` (${item.dimensiones.ancho}mm x ${item.dimensiones.alto}mm)` : ''}`} />
                                    ))}
                                </DesgloseSection>
                            )}
                            {/* Vidrio */}
                            {result.desglose.vidrios && (
                                <DesgloseSection title="Vidrio" icon="fa-square" color="purple" total={result.resumen.total_vidrios}>
                                    <DesgloseItem color="purple"
                                        left={`${result.desglose.vidrios.codigo} - ${result.desglose.vidrios.descripcion}`}
                                        right={result.desglose.vidrios.precio_total}
                                        detail={`${result.desglose.vidrios.ancho_mm}mm x ${result.desglose.vidrios.alto_mm}mm = ${result.desglose.vidrios.area_m2}m2 x $${result.desglose.vidrios.precio_m2}/m2${result.desglose.vidrios.cantidad_hojas > 1 ? ` x ${result.desglose.vidrios.cantidad_hojas} hojas` : ''}`} />
                                </DesgloseSection>
                            )}
                            {/* Tratamiento */}
                            {result.desglose.tratamiento && (
                                <DesgloseSection title="Tratamiento" icon="fa-paint-brush" color="yellow" total={result.resumen.total_tratamiento}>
                                    <DesgloseItem color="yellow"
                                        left={result.desglose.tratamiento.descripcion}
                                        right={result.desglose.tratamiento.precio_total}
                                        detail={`${result.desglose.tratamiento.peso_total_kg}kg x $${result.desglose.tratamiento.precio_kg}/kg`} />
                                </DesgloseSection>
                            )}
                            {/* Mano de obra */}
                            {result.desglose.mano_obra && result.resumen.total_mano_obra > 0 && (
                                <DesgloseSection title="Mano de Obra" icon="fa-hard-hat" color="orange" total={result.resumen.total_mano_obra}>
                                    <DesgloseItem color="orange"
                                        left="Horas Hombre"
                                        right={result.desglose.mano_obra.precio_total}
                                        detail={`${result.desglose.mano_obra.horas} hs x $${fmt(result.desglose.mano_obra.valor_hora)}/hora`} />
                                </DesgloseSection>
                            )}
                            {/* Opcionales */}
                            {result.desglose.opcionales && result.desglose.opcionales.length > 0 && (
                                <DesgloseSection title={`Opcionales (${result.desglose.opcionales.length})`} icon="fa-plus-circle" color="indigo" total={result.resumen.total_opcionales}>
                                    {result.desglose.opcionales.map((item, idx) => (
                                        <div key={idx} className="bg-white p-2 rounded text-sm">
                                            <div className="flex justify-between font-medium">
                                                <span className="text-gray-800">{item.codigo} - {item.nombre}</span>
                                                <span className="text-indigo-600">${fmt(item.precio_total)}</span>
                                            </div>
                                            <div className="text-xs text-gray-500 mt-0.5">
                                                {item.tipo === 'mosquitero' ? (
                                                    item.formulas && item.formulas.map((f, fi) => (
                                                        <div key={fi}>Cant: {f.cantidad} x {f.area_m2}m2 x ${(item.precio_m2 || 0).toLocaleString('es-AR')}/m2 = ${fmt(f.precio)}</div>
                                                    ))
                                                ) : (
                                                    <>
                                                        {item.perfiles && item.perfiles.map((p, pi) => (
                                                            <div key={`p${pi}`}>{p.codigo}: Cant {p.cantidad} x {p.longitud_mm}mm = ${fmt(p.precio_total)}</div>
                                                        ))}
                                                        {item.accesorios && item.accesorios.map((a, ai) => (
                                                            <div key={`a${ai}`}>{a.codigo}: Cant {a.cantidad} = ${fmt(a.precio_total)}</div>
                                                        ))}
                                                    </>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                                </DesgloseSection>
                            )}
                        </div>

                        <button onClick={guardar} disabled={saving}
                            className="mt-4 w-full bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 disabled:opacity-50 text-white py-3 rounded-xl font-bold text-sm flex items-center justify-center transition-all">
                            {saving ? <><i className="fas fa-spinner fa-spin mr-2"></i>Guardando...</> : <><i className="fas fa-check mr-2"></i>Agregar al presupuesto</>}
                        </button>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center py-16 text-slate-300">
                        <i className="fas fa-calculator text-6xl mb-4"></i>
                        <p className="font-semibold text-slate-400">Configura y calcula</p>
                        <p className="text-sm mt-1">El resultado aparece aca</p>
                    </div>
                )}
            </div>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('cotizador-modal-root'));
root.render(<CotizadorModal />);
})();
